// ============================================================
// ZHA Error Monitoring — fetches HA API and formats report
// ============================================================
const LQI_THRESHOLD = 50;
const MAX_LOG_LINES = 30;

const haUrl = $env.HA_URL;
const haToken = $env.HA_TOKEN;
const headers = { 'Authorization': `Bearer ${haToken}` };

// Fetch all three endpoints in parallel
const [errorLogRes, statesRes, logbookRes] = await Promise.all([
  fetch(`${haUrl}/api/error_log`, { headers }),
  fetch(`${haUrl}/api/states`, { headers }),
  fetch(`${haUrl}/api/logbook`, { headers })
]);

const errorLogRaw = await errorLogRes.text();
const states = await statesRes.json();
const logbook = await logbookRes.json();

const ZHA_PATTERN = /zha|zigbee/i;

// SECTION 1 — ZHA Error Log Entries
const errorLogLines = errorLogRaw
  .split('\n')
  .filter(line => line.trim().length > 0 && ZHA_PATTERN.test(line))
  .slice(-MAX_LOG_LINES);

let section1 = '## Section 1: ZHA Error Log Entries\n';
if (errorLogLines.length === 0) {
  section1 += '_No ZHA/Zigbee errors found in the HA error log._\n';
} else {
  section1 += `_${errorLogLines.length} matching line(s) (most recent ${MAX_LOG_LINES} shown):_\n\n`;
  section1 += '```\n' + errorLogLines.join('\n') + '\n```\n';
}

// SECTION 2 — Unavailable ZHA Devices
const isZHAEntity = (e) => {
  const attrs = e.attributes || {};
  return attrs.lqi !== undefined || attrs.rssi !== undefined;
};

const unavailableDevices = states.filter(e => e.state === 'unavailable' && isZHAEntity(e));

let section2 = '## Section 2: Unavailable ZHA Devices\n';
if (unavailableDevices.length === 0) {
  section2 += '_No unavailable ZHA devices._\n';
} else {
  section2 += `_${unavailableDevices.length} unavailable device(s):_\n\n`;
  section2 += '| Entity ID | Friendly Name | Last Changed |\n';
  section2 += '|-----------|--------------|-------------|\n';
  for (const e of unavailableDevices) {
    const name = e.attributes?.friendly_name ?? e.entity_id;
    const changed = e.last_changed
      ? new Date(e.last_changed).toLocaleString('en-US', { timeZone: 'America/New_York' })
      : 'Unknown';
    section2 += `| \`${e.entity_id}\` | ${name} | ${changed} |\n`;
  }
  section2 += '\n';
}

// SECTION 3 — Weak Signal Devices (LQI < threshold)
const weakSignalDevices = states
  .filter(e => {
    const lqi = e.attributes?.lqi;
    return lqi !== undefined && Number(lqi) < LQI_THRESHOLD;
  })
  .sort((a, b) => Number(a.attributes.lqi) - Number(b.attributes.lqi));

let section3 = `## Section 3: Weak Signal Devices (LQI < ${LQI_THRESHOLD})\n`;
if (weakSignalDevices.length === 0) {
  section3 += `_No ZHA devices with LQI below ${LQI_THRESHOLD}._\n`;
} else {
  section3 += `_${weakSignalDevices.length} device(s) with weak signal:_\n\n`;
  section3 += '| Entity ID | Friendly Name | LQI | RSSI | Last Seen |\n';
  section3 += '|-----------|--------------|-----|------|----------|\n';
  for (const e of weakSignalDevices) {
    const attrs = e.attributes || {};
    const name = attrs.friendly_name ?? e.entity_id;
    const lqi = attrs.lqi ?? 'N/A';
    const rssi = attrs.rssi ?? 'N/A';
    const lastSeen = attrs.last_seen
      ? new Date(attrs.last_seen).toLocaleString('en-US', { timeZone: 'America/New_York' })
      : 'Unknown';
    section3 += `| \`${e.entity_id}\` | ${name} | ${lqi} | ${rssi} | ${lastSeen} |\n`;
  }
  section3 += '\n';
}

// SECTION 4 — ZHA Logbook Events
const zhaEvents = logbook
  .filter(e =>
    ZHA_PATTERN.test(e.name || '') ||
    ZHA_PATTERN.test(e.message || '') ||
    ZHA_PATTERN.test(e.domain || '') ||
    ZHA_PATTERN.test(e.entity_id || '')
  )
  .slice(0, 20);

let section4 = '## Section 4: Recent ZHA Logbook Events\n';
if (zhaEvents.length === 0) {
  section4 += '_No recent ZHA logbook events._\n';
} else {
  section4 += `_${zhaEvents.length} recent event(s):_\n\n`;
  for (const e of zhaEvents) {
    const when = e.when
      ? new Date(e.when).toLocaleString('en-US', { timeZone: 'America/New_York' })
      : 'Unknown';
    section4 += `- **${when}** — \`${e.entity_id ?? e.domain ?? 'unknown'}\` — ${e.message ?? e.name ?? 'no message'}\n`;
  }
  section4 += '\n';
}

// SUMMARY
const runTime = new Date().toLocaleString('en-US', { timeZone: 'America/New_York' });
const summary =
  `# ZHA Health Report\n` +
  `**Run time:** ${runTime}\n\n` +
  `**Summary:** ` +
  `${errorLogLines.length} error log entries | ` +
  `${unavailableDevices.length} unavailable devices | ` +
  `${weakSignalDevices.length} weak signal devices | ` +
  `${zhaEvents.length} logbook events\n\n` +
  `---\n\n`;

const fullReport = summary + section1 + '\n' + section2 + '\n' + section3 + '\n' + section4;

return [{ json: { report: fullReport } }];
